  "questionProse": [
    "कौन सा एल्गोरिदम अक्सर गैर-नकारात्मक किनारों वाले वेटेड ग्राफ में सबसे छोटा पथ खोजने के लिए उपयोग किया जाता है?"
  ],
  "explanationProse": [
    "डिज्क्स्ट्रा एल्गोरिदम अक्सर गैर-नकारात्मक किनारा वज़न वाले ग्राफ में सबसे छोटा पथ खोजने के लिए उपयोग किया जाता है। यह प्राथमिकता कतार (priority queue) का उपयोग करके सबसे छोटी दूरी को कुशलता से निर्धारित करता है।"
  ]
